const body = $input.first().json.body || $input.first().json;
const messageType = body.data?.messageType || 'unknown';
const phone = body.data?.key?.remoteJid?.replace('@s.whatsapp.net', '').replace('@g.us', '') || '';
const fromMe = body.data?.key?.fromMe || false;
const text = body.data?.message?.conversation || body.data?.message?.extendedTextMessage?.text || '';
const hasImage = messageType === 'imageMessage';
const instanceName = body.instance || '';
const mediaUrl = body.data?.message?.imageMessage?.url || null;

if (fromMe || body.event !== 'messages.upsert') {
  return [{ json: { skip: true } }];
}

return [{ json: { skip: false, phone, text, hasImage, mediaUrl, messageType, instanceName } }];

const r = $input.first().json;
if (!r || !r.base64) {
  throw new Error('Evolution no devolvió base64 del comprobante.');
}
return [{ json: {
  base64Image: r.base64,
  mimeType: r.mimetype || 'image/jpeg',
  phone: $('Parsear Mensaje').first().json.phone
} }];

