parameters.jsCode:
const apiResponse = $input.first().json;
const content = apiResponse.choices?.[0]?.message?.content || '';
const pendingOrder = $('Buscar Orden Pendiente').first().json;

let paymentData;
try {
  const match = content.match(/\{[\s\S]*\}/);
  paymentData = JSON.parse(match ? match[0] : content);
} catch (e) {
  return [{ json: { isValid: false, reason: 'No se pudo leer el comprobante. Por favor envia una imagen mas clara.' } }];
}

if (!pendingOrder?.order_id) {
  return [{ json: { isValid: false, reason: 'No encontramos una orden pendiente de pago para tu numero.' } }];
}

const montoEsperado = parseFloat(pendingOrder.total_amount);
const montoRecibido = parseFloat(paymentData.monto);
const isValid = !isNaN(montoRecibido) && Math.abs(montoEsperado - montoRecibido) < 0.5;

const nroOperacion = (paymentData.nro_operacion ?? '').toString().trim() || 'N/D';
const destinatario = (paymentData.destinatario ?? '').toString().trim() || 'N/D';
const fechaHora = (paymentData.fecha_hora ?? '').toString().trim() || 'N/D';
const app = (paymentData.app ?? '').toString().trim() || 'N/D';

const adminNotes =
  `Pago ${app} | N. operacion: ${nroOperacion} | Monto comprobante: S/${montoRecibido} ` +
  `| Esperado: S/${montoEsperado} | Destinatario: ${destinatario} | Fecha: ${fechaHora}`;

return [{ json: {
  isValid,
  montoEsperado,
  montoRecibido: isNaN(montoRecibido) ? 0 : montoRecibido,
  nroOperacion,
  destinatario,
  fechaHora,
  app,
  orderId: pendingOrder.order_id,
  adminNotes,
  reason: isValid ? 'OK' : `Monto incorrecto. Se esperaba S/${montoEsperado}, se detecto S/${montoRecibido}`
} }];

